package com.datasophon.common.utils;


import cn.hutool.core.util.HexUtil;
import cn.hutool.core.util.StrUtil;
import cn.hutool.crypto.SmUtil;
import cn.hutool.crypto.symmetric.SM4;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import java.nio.charset.StandardCharsets;


public class PasswordSupport {

    private static final Logger logger = LoggerFactory.getLogger(PasswordSupport.class);

    private static SM4 sm4 = SmUtil.sm4(HexUtil.decodeHex("7ddc211e28feb630bd87c66acd8bccd6"));


    public static String encryptDbPassword(String password) {
        if (StrUtil.isBlank(password)) {
            return password;
        }

        return sm4.encryptHex(password);
    }

    public static String decryptDbPassword(String encryptPassword) {

        if (StrUtil.isBlank(encryptPassword)) {
            return encryptPassword;
        }
        return sm4.decryptStr(encryptPassword, StandardCharsets.UTF_8);
    }


    public static void main(String[] args) {
        String sourcePassword = PasswordSupport.encryptDbPassword("123456");
        System.out.println(sourcePassword);
        System.out.println(PasswordSupport.decryptDbPassword(""));
    }



}
